import React from "react";
import { Zap, Shield, Code } from "lucide-react";
import { NavigationMenu, NavigationMenuItem, NavigationMenuLink, NavigationMenuList, NavigationMenuContent, NavigationMenuTrigger, navigationMenuTriggerStyle } from "@/components/ui/navigation-menu";

const data = {
  "productCategories": [
    {
      "title": "Electronics",
      "items": [
        "Laptops",
        "Phones",
        "Tablets",
        "Accessories"
      ]
    },
    {
      "title": "Clothing",
      "items": [
        "Men",
        "Women",
        "Kids",
        "Sports"
      ]
    },
    {
      "title": "Home",
      "items": [
        "Furniture",
        "Decor",
        "Kitchen",
        "Garden"
      ]
    }
  ],
  "solutions": [
    {
      "title": "For Startups",
      "icon": "Zap",
      "description": "Affordable plans designed for growing businesses."
    },
    {
      "title": "For Enterprise",
      "icon": "Shield",
      "description": "Enterprise-grade security and scalability."
    },
    {
      "title": "For Developers",
      "icon": "Code",
      "description": "APIs and tools to build custom integrations."
    }
  ],
  "pricingLink": {
    "label": "Pricing",
    "href": "#"
  }
};

const solutionIcons = { Zap, Shield, Code };

export default function NavigationMenuMegaExample() {
  return (
    <NavigationMenu>
      <NavigationMenuList className="flex flex-col lg:flex-row gap-2">
        {data.productCategories.map((cat) => (
          <NavigationMenuItem key={cat.title}>
            <NavigationMenuTrigger>{cat.title}</NavigationMenuTrigger>
            <NavigationMenuContent>
              <ul className="grid w-[400px] gap-3 p-4">
                {cat.items.map((item) => (
                  <li key={item}>
                    <NavigationMenuLink href="#">{item}</NavigationMenuLink>
                  </li>
                ))}
              </ul>
            </NavigationMenuContent>
          </NavigationMenuItem>
        ))}
        {data.solutions.map((s) => (
          <NavigationMenuItem key={s.title}>
            <NavigationMenuTrigger>{s.title}</NavigationMenuTrigger>
            <NavigationMenuContent>
              <ul className="grid w-[400px] gap-3 p-4">
                <li>
                  <NavigationMenuLink asChild>
                    <a href="#" className="block select-none space-y-1 rounded-md p-3 leading-none no-underline outline-none hover:bg-accent">
                      <div className="text-sm font-medium leading-none">{s.title}</div>
                      <p className="line-clamp-2 text-sm text-muted-foreground">{s.description}</p>
                    </a>
                  </NavigationMenuLink>
                </li>
              </ul>
            </NavigationMenuContent>
          </NavigationMenuItem>
        ))}
        <NavigationMenuItem>
          <NavigationMenuLink className={navigationMenuTriggerStyle()} href={data.pricingLink.href}>
            {data.pricingLink.label}
          </NavigationMenuLink>
        </NavigationMenuItem>
      </NavigationMenuList>
    </NavigationMenu>
  );
}
